/**
 * Simple in-memory + localStorage cache with stale-while-revalidate.
 * Provides instant page loads by returning cached data immediately,
 * then re-fetching in the background.
 */

const memCache = {}

const TTL = {
  dashboard: 60_000,       // 60s ΓÇö financial snapshot
  transactions: 30_000,    // 30s ΓÇö changes more often
  budgets: 120_000,        // 2m ΓÇö rarely changes
  metals: 600_000,         // 10m ΓÇö market rates
  wallets: 120_000,
  goals: 120_000,
  receivables: 60_000,
  stocks: 300_000,
}

function lsKey(key) { return `fintrack_cache_${key}` }

/** Get value from memory ΓåÆ localStorage ΓåÆ null */
export function getCached(key) {
  const getTTL = (k) => k.startsWith('stocks') ? TTL.stocks : (TTL[k] ?? 60_000)

  // 1. Memory hit
  if (memCache[key]) {
    const { data, ts } = memCache[key]
    if (Date.now() - ts < getTTL(key)) return data
  }
  // 2. localStorage hit
  try {
    const raw = localStorage.getItem(lsKey(key))
    if (raw) {
      const { data, ts } = JSON.parse(raw)
      memCache[key] = { data, ts }   // prime memory cache
      if (Date.now() - ts < getTTL(key)) return data
    }
  } catch {}
  return null
}

/** Store value in memory + localStorage */
export function setCached(key, data) {
  const entry = { data, ts: Date.now() }
  memCache[key] = entry
  try { localStorage.setItem(lsKey(key), JSON.stringify(entry)) } catch {}
}

/** Invalidate a cache entry (force refresh next time) */
export function invalidateCache(key) {
  delete memCache[key]
  try { localStorage.removeItem(lsKey(key)) } catch {}
}

/** Invalidate all cache entries */
export function invalidateAll() {
  Object.keys(memCache).forEach(k => delete memCache[k])
  try {
    Object.keys(localStorage)
      .filter(k => k.startsWith('fintrack_cache_'))
      .forEach(k => localStorage.removeItem(k))
  } catch {}
}

import { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react'

const API_BASE = import.meta.env.VITE_API_BASE_URL || import.meta.env.VITE_API_URL || 'http://localhost:8000'
const AuthContext = createContext(null)

// Decode JWT payload without a library
function decodeToken(token) {
  try {
    return JSON.parse(atob(token.split('.')[1]))
  } catch {
    return null
  }
}

// Returns token if valid and not expired, null otherwise
function getValidToken() {
  const t = localStorage.getItem('token')
  if (!t) return null
  const payload = decodeToken(t)
  if (!payload) {
    localStorage.removeItem('token')
    localStorage.removeItem('user')
    return null
  }
  // Expired
  if (payload.exp && Date.now() / 1000 >= payload.exp) {
    localStorage.removeItem('token')
    localStorage.removeItem('user')
    return null
  }
  return t
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(() => {
    try { return JSON.parse(localStorage.getItem('user')) } catch { return null }
  })
  const [token, setToken] = useState(getValidToken)
  const refreshTimerRef = useRef(null)

  // ΓöÇΓöÇ Refresh access token via HTTP-only cookie ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const refreshAccessToken = useCallback(async () => {
    try {
      const res = await fetch(`${API_BASE}/auth/refresh`, {
        method: 'POST',
        credentials: 'include',   // Send the HTTP-only refresh cookie
      })
      if (!res.ok) {
        // Refresh failed ΓÇö force logout
        setToken(null)
        setUser(null)
        localStorage.removeItem('token')
        localStorage.removeItem('user')
        return null
      }
      const data = await res.json()
      localStorage.setItem('token', data.access_token)
      setToken(data.access_token)
      // Schedule next refresh
      scheduleRefresh(data.expires_in)
      return data.access_token
    } catch {
      return null
    }
  }, [])

  // ΓöÇΓöÇ Schedule proactive refresh 30s before expiry ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const scheduleRefresh = useCallback((expiresInSeconds) => {
    if (refreshTimerRef.current) clearTimeout(refreshTimerRef.current)
    const delay = Math.max((expiresInSeconds - 30) * 1000, 0)
    refreshTimerRef.current = setTimeout(() => {
      refreshAccessToken()
    }, delay)
  }, [refreshAccessToken])

  // On mount: schedule refresh based on stored token's remaining lifetime
  useEffect(() => {
    if (!token) return
    const payload = decodeToken(token)
    if (!payload?.exp) return
    const remainingSeconds = payload.exp - Date.now() / 1000
    if (remainingSeconds > 0) {
      scheduleRefresh(remainingSeconds)
    } else {
      // Already expired ΓÇö try to refresh immediately
      refreshAccessToken()
    }
    return () => {
      if (refreshTimerRef.current) clearTimeout(refreshTimerRef.current)
    }
  }, []) // run once on mount

  // ΓöÇΓöÇ Login: store access token, schedule refresh ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const login = (accessToken, userData, expiresIn) => {
    localStorage.setItem('token', accessToken)
    localStorage.setItem('user', JSON.stringify(userData))
    setToken(accessToken)
    setUser(userData)
    if (expiresIn) scheduleRefresh(expiresIn)
  }

  // ΓöÇΓöÇ Logout: clear everything + call server to clear cookie ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const logout = async () => {
    try {
      await fetch(`${API_BASE}/auth/logout`, {
        method: 'POST',
        credentials: 'include',    // Send cookie so server can blacklist it
      })
    } catch {
      // Best-effort ΓÇö still clear client state
    }
    if (refreshTimerRef.current) clearTimeout(refreshTimerRef.current)
    localStorage.removeItem('token')
    localStorage.removeItem('user')
    setToken(null)
    setUser(null)
  }

  return (
    <AuthContext.Provider value={{ user, token, login, logout, refreshAccessToken, isAuth: !!token }}>
      {children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => useContext(AuthContext)

/**
 * useDashboard
 * Encapsulates all dashboard data-fetching, stale-while-revalidate caching,
 * loading state, and manual refresh. Dashboard.jsx only handles rendering.
 */
import { useState, useCallback, useEffect } from 'react'
import api from '../api/axios'
import { getCached, setCached, invalidateCache } from '../api/cache'

export function useDashboard() {
  const [data, setData]           = useState(() => getCached('dashboard'))
  const [loading, setLoading]     = useState(!getCached('dashboard'))
  const [refreshing, setRefreshing] = useState(false)
  const [error, setError]         = useState(null)

  const fetch = useCallback(async (silent = false) => {
    // silent = true ΓåÆ don't show skeleton, just spin the refresh icon
    if (!silent && !getCached('dashboard')) {
      setLoading(true)
    } else {
      setRefreshing(true)
    }
    setError(null)
    try {
      const res = await api.get('/dashboard')
      setCached('dashboard', res.data)
      setData(res.data)
    } catch (err) {
      setError(err?.response?.data?.detail || 'Failed to load dashboard')
    } finally {
      setLoading(false)
      setRefreshing(false)
    }
  }, [])

  // Initial load on mount
  useEffect(() => { fetch() }, [fetch])

  const refresh = useCallback(() => {
    invalidateCache('dashboard')
    fetch(true)
  }, [fetch])

  return { data, loading, refreshing, error, refresh, refetch: fetch }
}

import { useState, useCallback, useEffect } from 'react'
import api from '../api/axios'
import { getCached, setCached, invalidateCache } from '../api/cache'
import toast from 'react-hot-toast'

export function useStocks(range = '1m') {
  const cacheKey = `stocks_${range}`
  const [data, setData] = useState(() => getCached(cacheKey) || null)
  const [loading, setLoading] = useState(!getCached(cacheKey))
  const [refreshing, setRefreshing] = useState(false)
  const [error, setError] = useState(null)

  // Optimistic cache swap on range change
  useEffect(() => {
    const cached = getCached(cacheKey)
    if (cached) {
      setData(cached)
      setLoading(false)
    }
  }, [cacheKey])

  const fetchStocks = useCallback(async (silent = false) => {
    const cached = getCached(cacheKey)

    if (!silent && !cached) {
      // Don't set full loading if we already have some data (stale data)
      // This prevents the whole page from unmounting.
      setRefreshing(true)
    } else {
      setRefreshing(true)
    }
    setError(null)

    try {
      const res = await api.get(`/stocks/market-indices?range=${range}`)
      setCached(cacheKey, res.data)
      setData(res.data)
    } catch (err) {
      setError(err?.response?.data?.detail || 'Failed to load stock indices')
      if (!silent) toast.error('Failed to load stock data')
    } finally {
      setLoading(false)
      setRefreshing(false)
    }
  }, [range, cacheKey])

  useEffect(() => {
    fetchStocks()
  }, [fetchStocks])

  const refresh = useCallback(() => {
    invalidateCache(cacheKey)
    fetchStocks(true)
  }, [fetchStocks, cacheKey])

  return {
    data,
    loading: loading && !data, // Only truly "loading" if we have absolutely no data
    refreshing,
    error,
    refresh,
    fetchStocks
  }
}

/**
 * useTransactions
 * Encapsulates paginated transaction fetching, filtering, search debounce,
 * categories loading, and stale-while-revalidate caching.
 * Extracted from Transactions.jsx.
 */
import { useState, useEffect, useCallback } from 'react'
import api from '../api/axios'
import { getCached, setCached, invalidateCache } from '../api/cache'
import toast from 'react-hot-toast'

const PAGE_LIMIT = 50

export function useTransactions() {
  const [txns, setTxns]             = useState(() => getCached('transactions') || [])
  const [categories, setCategories] = useState(() => getCached('categories') || [])
  const [loading, setLoading]       = useState(!getCached('transactions'))
  const [loadingMore, setLoadingMore] = useState(false)
  const [currentPage, setCurrentPage] = useState(1)
  const [hasMore, setHasMore]       = useState(false)
  const [totalCount, setTotalCount] = useState(0)

  // ΓöÇΓöÇ Filters ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const [filterWallet,   setFilterWallet]   = useState('')
  const [filterType,     setFilterType]     = useState('')
  const [filterCategory, setFilterCategory] = useState('')
  const [searchQuery,    setSearchQuery]    = useState('')

  // ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const isFiltered = !!(filterWallet || filterType || filterCategory || searchQuery.length > 2)

  // ΓöÇΓöÇ Fetch (supports page param for load-more) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const fetchTxns = useCallback(async (opts = {}) => {
    const { page = 1, silent = false } = opts
    const hasCache = getCached('transactions')

    if (page === 1) {
      if (!silent && (!hasCache || isFiltered)) setLoading(true)
    } else {
      setLoadingMore(true)
    }

    try {
      const params = { page, limit: PAGE_LIMIT }
      if (filterWallet)         params.wallet   = filterWallet
      if (filterType)           params.type     = filterType
      if (filterCategory)       params.category = filterCategory
      if (searchQuery.length > 2) params.search = searchQuery

      const res     = await api.get('/transactions', { params })
      const fetched = res.data.transactions

      setHasMore(res.data.has_more ?? false)
      setTotalCount(res.data.total_count ?? fetched.length)
      setCurrentPage(page)

      if (page === 1) {
        const unfiltered = !filterWallet && !filterType && !filterCategory && searchQuery.length <= 2
        if (unfiltered) setCached('transactions', fetched)
        setTxns(fetched)
      } else {
        setTxns(prev => [...prev, ...fetched])
      }
    } catch {
      toast.error('Failed to load transactions')
    } finally {
      setLoading(false)
      setLoadingMore(false)
    }
  }, [filterWallet, filterType, filterCategory, searchQuery, isFiltered])

  // ΓöÇΓöÇ Fetch categories ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const fetchCategories = useCallback(async () => {
    try {
      const res = await api.get('/categories')
      setCached('categories', res.data.categories)
      setCategories(res.data.categories)
    } catch { /* non-critical */ }
  }, [])

  // ΓöÇΓöÇ Mount: load categories once ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => { fetchCategories() }, [fetchCategories])

  // ΓöÇΓöÇ Debounced re-fetch on filter change ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    const timer = setTimeout(() => fetchTxns({ page: 1 }), 300)
    return () => clearTimeout(timer)
  }, [filterWallet, filterType, filterCategory, searchQuery])

  // ΓöÇΓöÇ Load more (next page, appends) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const loadMore = useCallback(() => {
    fetchTxns({ page: currentPage + 1 })
  }, [fetchTxns, currentPage])

  // ΓöÇΓöÇ Force full refresh after mutations ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const refresh = useCallback(() => {
    invalidateCache('transactions')
    fetchTxns({ page: 1, silent: false })
  }, [fetchTxns])

  return {
    txns,
    categories,
    loading,
    loadingMore,
    hasMore,
    totalCount,
    currentPage,
    // filters
    filterWallet,   setFilterWallet,
    filterType,     setFilterType,
    filterCategory, setFilterCategory,
    searchQuery,    setSearchQuery,
    // actions
    loadMore,
    refresh,
  }
}

/**
 * useWallets
 * Encapsulates wallet-balance fetching, per-wallet transaction listing,
 * and categories ΓÇö extracted from Wallets.jsx.
 */
import { useState, useEffect, useCallback } from 'react'
import api from '../api/axios'
import { getCached, setCached } from '../api/cache'
import toast from 'react-hot-toast'

export function useWallets() {
  const [balances, setBalances]     = useState(
    () => getCached('wallets') || { cash_balance: 0, upi_balance: 0, total_balance: 0 }
  )
  const [loading, setLoading]       = useState(!getCached('wallets'))
  const [recentTxns, setRecentTxns] = useState([])
  const [loadingTxns, setLoadingTxns] = useState(true)
  const [categories, setCategories] = useState(() => getCached('categories') || [])
  const [activeWallet, setActiveWallet] = useState('all')

  // ΓöÇΓöÇ Fetch balances ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const fetchBalances = useCallback(async () => {
    setLoading(true)
    try {
      const res = await api.get('/balances')
      setCached('wallets', res.data)
      setBalances(res.data)
    } catch {
      toast.error('Failed to load balances')
    } finally {
      setLoading(false)
    }
  }, [])

  // ΓöÇΓöÇ Fetch categories (for expense form) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const fetchCategories = useCallback(async () => {
    try {
      const res = await api.get('/categories')
      setCached('categories', res.data.categories)
      setCategories(res.data.categories)
    } catch { /* non-critical */ }
  }, [])

  // ΓöÇΓöÇ Fetch recent transactions for active wallet ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const fetchRecentTxns = useCallback(async (wallet = 'all') => {
    setLoadingTxns(true)
    try {
      const params = wallet !== 'all' ? { wallet, limit: 10 } : { limit: 10 }
      const res = await api.get('/transactions', { params })
      setRecentTxns(res.data.transactions)
    } catch {
      toast.error('Failed to load recent transactions')
    } finally {
      setLoadingTxns(false)
    }
  }, [])

  // ΓöÇΓöÇ Initial loads ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    fetchBalances()
    fetchCategories()
  }, [fetchBalances, fetchCategories])

  // Re-fetch transactions whenever the active wallet tab changes
  useEffect(() => {
    fetchRecentTxns(activeWallet)
  }, [activeWallet, fetchRecentTxns])

  // ΓöÇΓöÇ Public refresh (called after mutations) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const refresh = useCallback(() => {
    fetchBalances()
    fetchRecentTxns(activeWallet)
  }, [fetchBalances, fetchRecentTxns, activeWallet])

  return {
    balances,
    loading,
    recentTxns,
    loadingTxns,
    categories,
    activeWallet,
    setActiveWallet,
    refresh,
    fetchBalances,
  }
}

